package pages;

import com.microsoft.playwright.Page;
import com.microsoft.playwright.options.LoadState;
import base.BasePage;
import static pageobjects.LoginPage.*;
import static com.microsoft.playwright.assertions.PlaywrightAssertions.assertThat;

/**
 * LoginPageActions - Actions and assertions for Login functionality
 * Generated by Qentrix ScriptGenerationAgent
 */
public class LoginPageActions extends BasePage {

    public LoginPageActions(Page page) {
        super(page);
    }

    // ── Navigation ────────────────────────────────────────────────────────────

    public void navigateToLoginPage() {
        String baseUrl = getBaseUrl();
        page.navigate(baseUrl + LOGIN_URL);
        page.waitForLoadState(LoadState.DOMCONTENTLOADED);
    }

    // ── Actions ───────────────────────────────────────────────────────────────

    public void enterEmail(String email) {
        page.locator(EMAIL_INPUT).fill(email);
    }

    public void enterUsername(String username) {
        page.locator(USERNAME_INPUT).fill(username);
    }

    public void enterPassword(String password) {
        page.locator(PASSWORD_INPUT).fill(password);
    }

    public void clickLoginButton() {
        page.locator(LOGIN_BUTTON).click();
        page.waitForLoadState(LoadState.NETWORKIDLE);
    }

    public void submitLoginForm(String username, String password) {
        enterUsername(username);
        enterPassword(password);
        clickLoginButton();
    }

    public void submitLoginWithEmail(String email, String password) {
        enterEmail(email);
        enterPassword(password);
        clickLoginButton();
    }

    // ── Assertions ────────────────────────────────────────────────────────────

    public void verifyLoginPageDisplayed() {
        assertThat(page.locator(EMAIL_INPUT).or(page.locator(USERNAME_INPUT))).isVisible();
        assertThat(page.locator(PASSWORD_INPUT)).isVisible();
        assertThat(page.locator(LOGIN_BUTTON)).isVisible();
        assertThat(page.locator(REGISTER_LINK)).isVisible();
    }

    public void verifyLoginSuccess() {
        page.waitForLoadState(LoadState.NETWORKIDLE);
        assertThat(page.locator(DASHBOARD_INDICATOR)).isVisible();
    }

    public void verifyAuthTokenPresent() {
        page.waitForLoadState(LoadState.NETWORKIDLE);
        assertThat(page.locator(SUCCESS_TOKEN_ELEMENT)).isVisible();
    }

    public void verifyErrorMessageDisplayed() {
        assertThat(page.locator(ERROR_MESSAGE)).isVisible();
    }

    public void verifyInvalidCredentialsError() {
        assertThat(page.locator(INVALID_CREDENTIALS_MSG)).isVisible();
    }

    public void verifyMissingUsernameError() {
        assertThat(page.locator(MISSING_USERNAME_MSG)).isVisible();
    }

    public void verifyMissingPasswordError() {
        assertThat(page.locator(MISSING_PASSWORD_MSG)).isVisible();
    }

    public void verify401StatusCode() {
        // For API-based login validation
        // Response status verification would be handled by API test layer
        // Placeholder for UI-equivalent validation
        verifyErrorMessageDisplayed();
    }

    public void verify400StatusCode() {
        // For API-based validation of missing required fields
        verifyErrorMessageDisplayed();
    }
}
